<?php session_start(); if (!isset($_SESSION['user_id']) || $_SESSION['role'] != 'Student') { header("Location: index.php"); exit(); } require_once 'config/database.php'; $notif_query = "SELECT * FROM notifications ORDER BY created_at DESC LIMIT 5"; $notif_result = $conn->query($notif_query); $handout_query = "SELECT * FROM faculty_uploads ORDER BY uploaded_at DESC"; $handout_result = $conn->query($handout_query); $success = ""; if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['feedback'])) { $msg = $_POST['feedback']; $query = "INSERT INTO feedback (student_email, message, created_at) VALUES (?, ?, NOW())"; $stmt = $conn->prepare($query); $stmt->bind_param("ss", $_SESSION['email'], $msg); if ($stmt->execute()) { $success = "Feedback submitted!"; } } ?> <!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Student Dashboard</title><link rel="stylesheet" href="assets/css/style.css"></head><body><?php include 'includes/header.php'; ?><main class="container"><h1>Student Dashboard</h1><?php if ($success) echo "<div class='alert alert-success'>$success</div>"; ?><div class="grid-2"><div class="card"><h2>Notifications</h2><?php while($row = $notif_result->fetch_assoc()): ?><div class="notification-item"><h4><?php echo $row['title']; ?></h4><p><?php echo $row['message']; ?></p></div><?php endwhile; ?></div><div class="card"><h2>Course Handouts</h2><?php while($row = $handout_result->fetch_assoc()): ?><div class="handout-item"><p><?php echo $row['title']; ?></p><a href="backend/file-download.php?file_id=<?php echo $row['id']; ?>" class="btn btn-primary">Download</a></div><?php endwhile; ?></div></div><div class="card"><h2>Submit Feedback</h2><form method="POST"><textarea name="feedback" class="form-input" rows="4" placeholder="Your feedback..." required></textarea><button type="submit" class="btn btn-primary">Submit</button></form></div></main><?php include 'includes/footer.php'; ?></body></html>